# File: guardrails.py
"""Safety guardrails to prevent dangerous self-modifications."""
import os
from src import config

FORBIDDEN_KEYWORDS = [
    "rm -rf", "shutil.rmtree", "os.remove", "os.rmdir",
    "eval(", "exec(", "subprocess.call", "os.system", "subprocess.run",
    "__import__(", "importlib", "compile(", "ctypes",
    "requests.post", "urllib.request", "socket.",
]

FORBIDDEN_FILES = [
    ".env", ".env.local", ".env.production", ".gitconfig",
    "id_rsa", "id_ed25519", "*.key", "*.pem", "secrets.json",
]

def is_path_safe(path: str) -> bool:
    """Check if a file path is safe to modify."""
    path = os.path.abspath(path)
    repo_root = os.path.abspath(os.path.join(os.path.dirname(__file__), ".."))
    if not path.startswith(repo_root):
        return False
    for forbidden in config.FORBIDDEN_PATHS + FORBIDDEN_FILES:
        if forbidden in path or path.endswith(forbidden):
            return False
    return True

def is_code_safe(code: str) -> tuple[bool, str]:
    """Check if generated code contains dangerous patterns."""
    lines = code.splitlines()
    if len(lines) > config.MAX_PATCH_LINES:
        return False, f"Patch too large: {len(lines)} lines > {config.MAX_PATCH_LINES}"
    for keyword in FORBIDDEN_KEYWORDS:
        if keyword in code:
            return False, f"Forbidden keyword found: {keyword}"
    return True, ""

def review_patch(file_path: str, old_code: str, new_code: str) -> tuple[bool, str]:
    """Full review pipeline before applying any patch."""
    if not is_path_safe(file_path):
        return False, f"Path not safe: {file_path}"
    safe, reason = is_code_safe(new_code)
    if not safe:
        return False, reason
    return True, ""
